@auth_routes.get("/csrf-token")
def issue_anon_csrf_token():
    """
    Provide an anonymous CSRF token for unauthenticated clients.
    This is the only endpoint that is exempt from CSRF checks.
    Requires: no auth, no CSRF token
    """
    token = token_urlsafe(32)
    response = JSONResponse({"csrf_token": token}, status_code=HttpStatus.OK)
    Csrf.issue_anon_csrf_token(response, token=token)
    return response


@auth_routes.get("/csrf")
def get_csrf_snapshot(request: Request):
    """
    Return authenticated CSRF cookie values for logged-in clients.
    Requires: a valid access or refresh JWT cookie.
    """
    JWTService.require_authenticated_cookie(request)
    response = JSONResponse(
        {
            "csrf_access_token": JWTService.get_access_csrf_cookie(request),
            "csrf_refresh_token": JWTService.get_refresh_csrf_cookie(request),
            "anon_csrf": "",
        },
        status_code=HttpStatus.OK,
    )
    Csrf.clear_anon_csrf(response)
    return response


